function selectZone(name){if(!zones[name])return;active=name;activeLegendCategory=null;selectedOriginalId=null;document.querySelectorAll('.original-feature').forEach(x=>x.classList.remove('feature-selected'));document.querySelectorAll('.zone').forEach(z=>z.classList.toggle('selected',z.dataset.zone===name));const z=zones[name];
  document.querySelector('#detailPanel').style.visibility='visible';document.querySelector('#detailType').textContent='Material zone';document.querySelector('#detailName').textContent=name;document.querySelector('#detailConfidence').textContent=z.confidence+'%';document.querySelector('#confidenceInput').value=z.confidence;document.querySelector('#confidenceBar').style.width=z.confidence+'%';document.querySelector('#detailDepth').textContent=z.depth;document.querySelector('#detailVolume').textContent=z.volume;document.querySelector('#detailGrade').innerHTML=`${z.grade} <small>g/t</small>`;document.querySelector('#detailNotes').textContent=z.notes;document.querySelector('#detailStatus').textContent=z.status||'INTERPRETED';document.querySelector('#detailUpdated').textContent=z.updated||'18 Jun 2026';document.querySelector('#detailAccent').style.background=z.color;document.querySelector('#mineralChips').innerHTML=z.minerals.map(m=>`<span contenteditable="${zoneDataEditing}">${m}</span>`).join('');applyZoneConfidence(name);renderLayers(document.querySelector('#layerSearch').value);renderUserLayers()}
