function flash(msg){toast.textContent=msg;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2200)}
function addInitialSamples(){const g=document.querySelector('#samples');g.innerHTML='';const traces=[...document.querySelectorAll('#drillholes path')];let index=0;traces.forEach((trace,hole)=>{const length=trace.getTotalLength(),distances=[20];for(let distance=60;distance<length;distance+=60)distances.push(distance);distances.forEach((distance,interval)=>{const p=trace.getPointAtLength(Math.min(distance,length-1)),c=document.createElementNS('http://www.w3.org/2000/svg','circle');c.setAttribute('class','sample');c.setAttribute('cx',p.x);c.setAttribute('cy',p.y);c.setAttribute('r',2);c.dataset.sampleName=`DH${hole+1} · ${interval?'Interval '+interval:'Top sample'}`;c.dataset.sampleLink='';c.setAttribute('fill','#f4b860');g.append(c);index++})});defaultSampleCount=index;samples=index;document.querySelector('#sampleCount').textContent=`${samples} points`}
function applyMapTransform(){geoMap.style.transform=`translate(${panX}px,${panY}px) scale(${zoom})`}
function setZoom(v){zoom=Math.min(1.6,Math.max(.7,v));applyMapTransform();geoMap.style.setProperty('--inverse-zoom',1/zoom);document.querySelector('#zoomLevel').textContent=Math.round(zoom*100)+'%'}
function layerPath(points,closed=true){if(!points.length)return'';return points.map((p,i)=>`${i?'L':'M'}${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(' ')+(closed?' Z':'')}
function checkpoint(){history.push(JSON.stringify({userLayers,markings,legendState,originalEdits,presetPathEdits}));if(history.length>30)history.shift()}
function restoreSnapshot(raw){if(!raw)return;Object.keys(zones).forEach(k=>delete zones[k]);Object.assign(zones,JSON.parse(JSON.stringify(baseZones)));const state=JSON.parse(raw);userLayers=state.userLayers||[];markings=state.markings||[];legendState=state.legendState||JSON.parse(JSON.stringify(legendDefaults));originalEdits=state.originalEdits||{};presetPathEdits=state.presetPathEdits||{};userLayers.forEach(syncLayerData);saveUserLayers();saveMarkings();saveLegend();saveOriginalEdits();savePresetEdits();applyOriginalEdits();applyPresetEdits();renderUserLayers();renderMarkings();renderLayers();applyLegend();if(!zones[active])active='Advanced argillic';selectZone(active)}
