function categoryUsage(key){return userLayers.filter(x=>x.category===key).length+markings.filter(x=>x.category===key).length}
function deleteLegendCategory(key){const item=legendState[key];if(!item?.custom)return;const used=categoryUsage(key);if(used){flash(`Delete ${used} map object${used===1?'':'s'} first`);return}if(!confirm(`Delete the unused “${item.label}” legend?`))return;if(item.categoryType==='mineral'&&zones[item.label]?.definitionKey===key)delete zones[item.label];delete legendState[key];saveLegend();saveZoneMetadata();renderLayers();renderCustomLegendRows();applyLegend();flash('Legend deleted')}
function renderMaterialTypes(){const box=document.querySelector('#materialTypeList');if(!box)return;const defaults=Object.entries(baseZones).map(([name,z])=>({key:`material:${name}`,label:name,color:zones[name]?.color||z.color,minerals:z.minerals,custom:false})),custom=Object.entries(legendState).filter(([,v])=>v.custom&&v.categoryType==='mineral').map(([key,v])=>({key,label:v.label,color:zones[v.label]?.color||v.color,minerals:v.minerals||[],custom:true}));box.innerHTML=[...defaults,...custom].map(item=>{const used=item.custom?categoryUsage(item.key)>0:true;return`<div class="material-type" data-key="${item.key}"><span style="background:${item.color}"></span><b>${item.label}</b><button class="material-mark">Mark</button><button class="legend-delete ${used?'blocked':''}" title="${used?'Cannot delete marked objects':'Delete unused material type'}">×</button></div>`}).join('');box.querySelectorAll('.material-mark').forEach(btn=>btn.onclick=e=>{e.stopPropagation();activateMaterialType(btn.closest('.material-type').dataset.key)});box.querySelectorAll('.legend-delete').forEach(btn=>btn.onclick=e=>{e.stopPropagation();const key=btn.closest('.material-type').dataset.key;if(btn.classList.contains('blocked')){flash('Cannot delete marked objects');return}deleteLegendCategory(key)})}
function renderCustomLegendRows(){document.querySelectorAll('.legend-row.custom-category').forEach(x=>x.remove());const add=document.querySelector('#addLegendCategory');Object.entries(legendState).filter(([,v])=>v.custom&&v.categoryType!=='mineral').forEach(([key,item])=>{const used=categoryUsage(key),row=document.createElement('div');row.className='legend-row custom-category'+(activeLegendCategory===key?' category-active':'');row.dataset.key=key;row.innerHTML=`<span class="legend-symbol custom-category-symbol" style="color:${item.color}">${item.geometry==='point'?'◆':item.geometry==='line'?'╱':item.geometry==='area'?'⬡':'T'}</span><input class="legend-label" value="${item.label}" ${legendEditing?'':'disabled'}><input class="legend-color" type="color" value="${item.color}" ${legendEditing?'':'disabled'}><label class="legend-toggle"><input type="checkbox" ${item.visible?'checked':''}><i></i></label><button class="legend-use">Mark</button><button class="legend-delete" ${used?'disabled':''} title="${used?'Delete its map objects first':'Delete unused legend'}">×</button>`;row.querySelector('.legend-use').onclick=e=>{e.stopPropagation();activateLegendCategory(key)};row.querySelector('.legend-delete').onclick=e=>{e.stopPropagation();deleteLegendCategory(key)};row.querySelector('.legend-toggle input').onchange=e=>{checkpoint();item.visible=e.target.checked;saveLegend();applyLegend()};row.querySelector('.legend-color').oninput=e=>{item.color=e.target.value;clearCategoryOverrides(key);saveLegend();applyLegend();renderUserLayers();renderMarkings()};add.before(row)});renderMaterialTypes()}
function activateMaterialType(key){setEditorMode('edit');clearSelectionForMarking();activeMaterialType=key;activeLegendCategory=key.startsWith('material:')?'layers':key;const item=key.startsWith('material:')?{label:key.slice(9),color:zones[key.slice(9)]?.color,minerals:zones[key.slice(9)]?.minerals}:legendState[key];document.querySelector('#categoryHint').innerHTML=`Marking with <b>${item.label}</b> · Mineral layer`;startLayerDraw('polygon')}
function clearSelectionForMarking(){selectedObject=null;selectedOriginalId=null;editingMarkId=null;document.querySelectorAll('.zone').forEach(z=>z.classList.remove('selected'));document.querySelectorAll('.original-feature').forEach(x=>x.classList.remove('feature-selected'));document.querySelector('#presetHandles').innerHTML='';document.querySelector('#selectionProperties').hidden=true;document.querySelector('#detailPanel').style.visibility='hidden'}
function activateLegendCategory(key){const item=legendState[key];if(!item||key==='layers')return;setEditorMode('edit');clearSelectionForMarking();activeMaterialType=null;activeLegendCategory=key;document.querySelectorAll('.legend-row').forEach(r=>r.classList.toggle('category-active',r.dataset.key===key));const hint=document.querySelector('#categoryHint');hint.classList.add('active');hint.innerHTML=`Marking with <b>${item.label}</b> · ${item.geometry}`;if(item.geometry==='area'){startLayerDraw('polygon');return}if(item.geometry==='line'){startLayerDraw('line');return}if(item.geometry==='point'||item.geometry==='text'){const point=item.geometry==='point',dialog=document.querySelector('#objectNameDialog');dialog.dataset.key=key;dialog.dataset.geometry=item.geometry;document.querySelector('#objectDialogEyebrow').textContent=point?'MAP POINT':'MAP LABEL';document.querySelector('#objectDialogTitle').textContent=point?'Name this point':'Add label text';document.querySelector('#objectDialogLabel').textContent=point?'Point name':'Label text';document.querySelector('#newObjectName').value=point?`${item.label} ${markings.length+1}`:'';dialog.showModal()}}
document.querySelector('#confirmObjectName').onclick=()=>{const dialog=document.querySelector('#objectNameDialog'),name=document.querySelector('#newObjectName').value.trim();if(!name){flash('Name is required');return}const text=dialog.dataset.geometry==='text';pendingMark={type:text?'text':'marker',material:null,category:dialog.dataset.key,sampleId:name,note:''};tagging=true;dialog.close();document.querySelector('#mapStage').style.cursor=text?'text':'crosshair';document.querySelector('#mapHint').textContent=text?'Click the map to place label':'Click the map to place point'};
