function applyOriginalEdits(){document.querySelectorAll('.original-feature').forEach(el=>{const edit=originalEdits[el.dataset.featureId]||{},base=edit.baseTransform||el.dataset.baseTransform||'';if(el.tagName==='text'){el.textContent=edit.text!==undefined?edit.text:el.dataset.baseText;if(edit.x!==undefined)el.setAttribute('x',edit.x);if(edit.y!==undefined)el.setAttribute('y',edit.y);if(edit.size)el.style.fontSize=`${edit.size}px`;const x=Number(el.getAttribute('x'))||0,y=Number(el.getAttribute('y'))||0,cleanBase=edit.rotation===undefined?base:base.replace(/rotate\([^)]*\)/g,'');el.setAttribute('transform',`${cleanBase} translate(${edit.dx||0} ${edit.dy||0})${edit.rotation===undefined?'':` rotate(${edit.rotation} ${x} ${y})`}`.trim())}else el.setAttribute('transform',`${base} translate(${edit.dx||0} ${edit.dy||0})`.trim());if(edit.color){const geom=legendState[el.dataset.category]?.geometry||legendDefaults[el.dataset.category]?.geometry;if(el.tagName==='text'||el.dataset.category==='samples'||geom==='area'||geom==='point')el.style.fill=edit.color;else el.style.stroke=edit.color}if(edit.size&&el.tagName==='circle')el.setAttribute('r',edit.size);else if(edit.size&&el.tagName!=='text')el.style.strokeWidth=edit.size;el.style.display=edit.hidden?'none':''})}
function savePresetEdits(){try{localStorage.setItem('terratag-preset-paths',JSON.stringify(presetPathEdits))}catch{flash('Zone edits saved for this session only')}}
