function loadZoneMetadata(){try{const saved=JSON.parse(localStorage.getItem('terratag-zone-data')||'{}');Object.entries(saved).forEach(([name,data])=>{if(zones[name]||data.custom)zones[name]={...(zones[name]||{}),...data}})}catch{}}
function applyPresetEdits(){document.querySelectorAll('.preset-zone').forEach(path=>{const edit=presetPathEdits[path.dataset.presetId]||{};const baseName=path.dataset.baseZone;path.setAttribute('d',edit.d||path.dataset.baseD);if(edit.name&&edit.name!==baseName&&zones[baseName]){zones[edit.name]={...zones[baseName],color:edit.color||zones[baseName].color};delete zones[baseName];path.dataset.zone=edit.name}else path.dataset.zone=baseName;if(edit.color)path.style.fill=edit.color;path.style.opacity=.88*((zones[path.dataset.zone]?.confidence||100)/100);if(edit.scale){const b=path.getBBox(),cx=b.x+b.width/2,cy=b.y+b.height/2;path.setAttribute('transform',`translate(${cx} ${cy}) scale(${edit.scale}) translate(${-cx} ${-cy})`)}path.style.display=edit.hidden?'none':''})}
function tokenizePath(d){return d.match(/[A-Za-z]|-?\d*\.?\d+/g)||[]}
function rebuildPath(tokens){return tokens.join(' ')}
function keepLabelsInsideZone(name,path){const labels=document.querySelectorAll(`.labels text[data-label-zone="${name}"]`),bbox=path.getBBox();labels.forEach(label=>{const point=geoMap.createSVGPoint();point.x=Number(label.getAttribute('x'));point.y=Number(label.getAttribute('y'));if(path.isPointInFill?.(point))return;let best=null,bestDistance=Infinity;for(let y=bbox.y+5;y<bbox.y+bbox.height;y+=8){for(let x=bbox.x+5;x<bbox.x+bbox.width;x+=8){point.x=x;point.y=y;if(!path.isPointInFill?.(point))continue;const d=Math.hypot(x-Number(label.getAttribute('x')),y-Number(label.getAttribute('y')));if(d<bestDistance){best={x,y};bestDistance=d}}}if(!best)return;label.setAttribute('x',best.x);label.setAttribute('y',best.y);const transform=label.getAttribute('transform')||'',angle=transform.match(/rotate\((-?\d+(?:\.\d+)?)/)?.[1];if(angle)label.setAttribute('transform',`rotate(${angle} ${best.x} ${best.y})`);if(label.dataset.featureId)originalEdits[label.dataset.featureId]={...(originalEdits[label.dataset.featureId]||{}),x:best.x,y:best.y,baseTransform:label.getAttribute('transform')}})}
function initPresetZones(){try{presetPathEdits=JSON.parse(localStorage.getItem('terratag-preset-paths'))||{}}catch{presetPathEdits={}};if(!localStorage.getItem('terratag-sandwich-geometry-v2')){['zone-1','zone-2','zone-3','zone-4','zone-7'].forEach(id=>{if(presetPathEdits[id]){delete presetPathEdits[id].d;delete presetPathEdits[id].scale}});localStorage.setItem('terratag-sandwich-geometry-v2','1');savePresetEdits()}document.querySelectorAll('.zone:not(.user-layer)').forEach((path,i)=>{path.classList.add('preset-zone');path.dataset.presetId=`zone-${i}`;path.dataset.baseD=path.getAttribute('d');path.dataset.baseZone=path.dataset.zone;path.addEventListener('click',e=>{e.stopPropagation();if(mapPanned)return;if(editorMode==='edit')selectPresetPath(path);else selectZone(path.dataset.zone)})});applyPresetEdits()}
function selectPresetPath(path){selectedObject={kind:'zone',id:path.dataset.presetId,el:path};selectedOriginalId=null;selectZone(path.dataset.zone);const scale=presetPathEdits[path.dataset.presetId]?.scale||1;showSelectionProperties('Material zone',path.dataset.zone,path.style.fill||zones[path.dataset.zone].color,Math.round(scale*10));renderPresetHandles(path)}
function renderPresetHandles(path){const group=document.querySelector('#presetHandles');group.innerHTML='';if(editorMode!=='edit'||!path)return;const tokens=tokenizePath(path.getAttribute('d'));const numberIndexes=[];tokens.forEach((t,i)=>{if(!/[A-Za-z]/.test(t))numberIndexes.push(i)});for(let n=0;n<numberIndexes.length-1;n+=2){const xi=numberIndexes[n],yi=numberIndexes[n+1];const h=document.createElementNS('http://www.w3.org/2000/svg','circle');h.setAttribute('class','preset-handle');h.setAttribute('cx',tokens[xi]);h.setAttribute('cy',tokens[yi]);h.setAttribute('r',4);h.onpointerdown=e=>{e.stopPropagation();checkpoint();h.setPointerCapture(e.pointerId)};h.onpointermove=e=>{if(!h.hasPointerCapture(e.pointerId))return;const p=svgPoint(e);tokens[xi]=p.x.toFixed(1);tokens[yi]=p.y.toFixed(1);h.setAttribute('cx',tokens[xi]);h.setAttribute('cy',tokens[yi]);path.setAttribute('d',rebuildPath(tokens))};h.onpointerup=e=>{if(h.hasPointerCapture(e.pointerId))h.releasePointerCapture(e.pointerId);presetPathEdits[path.dataset.presetId]={...(presetPathEdits[path.dataset.presetId]||{}),d:path.getAttribute('d')};keepLabelsInsideZone(path.dataset.zone,path);savePresetEdits();saveOriginalEdits();flash('Zone boundary updated')};group.append(h)}}
