document.querySelector('#mapStage').addEventListener('pointerup',e=>{if(!panDrag||e.pointerId!==panDrag.id)return;mapPanned=panDrag.moved;if(document.querySelector('#mapStage').hasPointerCapture(e.pointerId))document.querySelector('#mapStage').releasePointerCapture(e.pointerId);panDrag=null;document.querySelector('#mapStage').classList.remove('panning');setTimeout(()=>{mapPanned=false},0)});
document.querySelector('#undoVertex').onclick=e=>{e.stopPropagation();draftPoints.pop();renderDraft()};document.querySelector('#cancelLayer').onclick=e=>{e.stopPropagation();cancelLayerDraw()};document.querySelector('#finishLayer').onclick=e=>{e.stopPropagation();finishLayerDraw()};
document.querySelector('#saveLayer').onclick=()=>{const name=document.querySelector('#layerName').value.trim();if(!name){flash('Name is required');return}checkpoint();const minerals=document.querySelector('#layerMinerals').value.split(',').map(x=>x.trim()).filter(Boolean);let saved;if(editingLayerId){saved=userLayers.find(l=>l.id===editingLayerId);const oldName=saved.name;Object.assign(saved,{name,color:document.querySelector('#layerColor').value,minerals,note:document.querySelector('#layerNote').value.trim()});if(oldName!==name&&zones[oldName]?.custom&&!userLayers.some(l=>l.id!==saved.id&&l.name===oldName))delete zones[oldName];syncLayerData(saved)}else{saved={id:`layer-${Date.now()}`,name,color:document.querySelector('#layerColor').value,minerals,note:document.querySelector('#layerNote').value.trim(),type:draftType,category:activeLegendCategory,points:draftPoints.map(p=>({...p})),confidence:100};userLayers.push(saved);syncLayerData(saved)}draftPoints=[];editingLayerId=null;document.querySelector('#drawPreview').innerHTML='';document.querySelector('#layerDialog').close();saveUserLayers();selectedObject={kind:'userLayer',id:saved.id};if(zones[saved.name]){active=saved.name;selectZone(active)}else{renderUserLayers();renderMarkIndex();document.querySelector('#detailPanel').style.visibility='hidden'}flash(`${saved.name} saved`)};
document.querySelector('#deleteLayer').onclick=()=>{const layer=userLayers.find(l=>l.id===editingLayerId);if(!layer)return;checkpoint();userLayers=userLayers.filter(l=>l.id!==editingLayerId);if(zones[layer.name]?.custom&&!zones[layer.name].definitionKey&&!userLayers.some(l=>l.name===layer.name))delete zones[layer.name];active='Advanced argillic';editingLayerId=null;document.querySelector('#layerDialog').close();saveUserLayers();renderUserLayers();renderLayers();selectZone(active);flash(`${layer.name} shape deleted`)};
document.querySelector('#layerDialog').addEventListener('close',()=>{if(draftPoints.length){draftPoints=[];document.querySelector('#drawPreview').innerHTML='';document.querySelector('#mapHint').textContent='Click a zone to inspect · Add a marking to annotate the section'}});
function updateCategorySymbolOptions(){const type=document.querySelector('#categoryType').value,geometry=type==='mineral'?'area':document.querySelector('#categoryGeometry').value,options={point:[['circle','Circle'],['square','Square'],['triangle','Triangle'],['diamond','Diamond'],['cross','Cross'],['star','Star'],['pipe','Pipe'],['drill','Drill-hole collar']],line:[['solid','Solid'],['dashed','Dashed'],['dotted','Dotted'],['double','Double'],['arrow','Arrowed']],area:[['solid','Solid fill'],['hatch','Hatching — Coming soon',true],['dots','Dots — Coming soon',true]],text:[['solid','Standard text']]};document.querySelector('#geometryField').hidden=type==='mineral';document.querySelector('#categorySymbol').innerHTML=options[geometry].map(([v,l,disabled])=>`<option value="${v}" ${disabled?'disabled':''}>${l}</option>`).join('')}
document.querySelector('#categoryGeometry').onchange=updateCategorySymbolOptions;
document.querySelector('#categoryType').onchange=updateCategorySymbolOptions;
document.querySelector('#addLegendCategory').onclick=()=>{document.querySelector('#categoryName').value='';document.querySelector('#categoryColor').value='#7c5cff';document.querySelector('#categoryType').value='mineral';document.querySelector('#categoryGeometry').value='point';updateCategorySymbolOptions();document.querySelector('#categoryDialog').showModal()};
document.querySelector('#saveCategory').onclick=()=>{const label=document.querySelector('#categoryName').value.trim();if(!label){flash('Category name is required');return}const categoryType=document.querySelector('#categoryType').value;if(categoryType==='mineral'&&zones[label]){flash(`${label} already exists in Material layers`);return}checkpoint();const key=`custom-${Date.now()}`,geometry=categoryType==='mineral'?'area':document.querySelector('#categoryGeometry').value,color=document.querySelector('#categoryColor').value;legendState[key]={label,color,visible:true,categoryType,geometry,symbol:document.querySelector('#categorySymbol').value,custom:true};if(categoryType==='mineral'){zones[label]={color,confidence:100,depth:'Not mapped',volume:'Not calculated',minerals:[],grade:'—',notes:'New material type. Click Mark to map its extent.',custom:true,definitionKey:key,status:'UNMAPPED'};active=label;saveZoneMetadata();renderLayers();const list=document.querySelector('#materialTypeList');list.hidden=false;document.querySelector('#toggleMaterialTypes').setAttribute('aria-expanded','true')}saveLegend();renderCustomLegendRows();applyLegend();document.querySelector('#categoryDialog').close();if(categoryType==='mineral'){const row=document.querySelector(`.material-type[data-key="${key}"]`);row?.classList.add('new-material');row?.scrollIntoView({block:'nearest'});selectZone(label)}flash(`${label} added${categoryType==='mineral'?' to Material layers':' — click Mark to use it'}`)};
document.querySelector('#editLegend').onclick=()=>{legendEditing=!legendEditing;const btn=document.querySelector('#editLegend');document.querySelectorAll('.legend-row:not(.locked-legend) .legend-label,.legend-row:not(.locked-legend) .legend-color').forEach(input=>input.disabled=!legendEditing);if(legendEditing){checkpoint();btn.textContent='Save';return}document.querySelectorAll('.legend-row:not(.locked-legend)').forEach(row=>{const key=row.dataset.key;legendState[key].label=row.querySelector('.legend-label').value.trim()||legendDefaults[key]?.label||'Untitled category';const next=row.querySelector('.legend-color').value;if(next!==legendState[key].color)clearCategoryOverrides(key);legendState[key].color=next});saveLegend();applyLegend();renderUserLayers();renderMarkings();btn.textContent='Edit';flash('Legend updated')};
document.querySelectorAll('.legend-color').forEach(input=>input.oninput=()=>{const key=input.closest('.legend-row').dataset.key;legendState[key].color=input.value;clearCategoryOverrides(key);saveLegend();applyLegend();renderUserLayers();renderMarkings()});
document.querySelectorAll('.legend-toggle input').forEach(input=>input.onchange=()=>{checkpoint();const key=input.closest('.legend-row').dataset.key;legendState[key].visible=input.checked;saveLegend();applyLegend()});
document.querySelector('#objectName').onchange=e=>{if(!selectedObject)return;const value=e.target.value.trim();if(!value)return;checkpoint();if(selectedObject.kind==='zone'){const path=selectedObject.el,old=path.dataset.zone;if(value!==old&&!zones[value]){zones[value]={...zones[old]};delete zones[old];path.dataset.zone=value;active=value;const edit=presetPathEdits[selectedObject.id]||{};presetPathEdits[selectedObject.id]={...edit,name:value,baseName:path.dataset.baseZone,color:path.style.fill||zones[value].color};savePresetEdits();renderLayers();selectZone(value)}}else if(selectedObject.kind==='userLayer'){const layer=userLayers.find(l=>l.id===selectedObject.id);if(layer){if(layer.type==='polygon'&&zones[layer.name]){delete zones[layer.name];layer.name=value;syncLayerData(layer);active=value}else layer.name=value;saveUserLayers();renderUserLayers();renderLayers()}}else if(selectedObject.kind==='mark'){const mark=markings.find(m=>m.id===selectedObject.id);if(mark){mark.sampleId=value;saveMarkings();renderMarkings()}}else if(selectedObject.kind==='original'){const edit=originalEdits[selectedObject.id]||{};edit.name=value;if(selectedObject.el.tagName==='text'){edit.text=value;selectedObject.el.textContent=value}originalEdits[selectedObject.id]=edit;saveOriginalEdits()}flash('Object renamed')};
document.querySelector('#objectColor').oninput=e=>{if(!selectedObject)return;const color=e.target.value;if(selectedObject.kind==='zone'){const path=selectedObject.el,name=path.dataset.zone;path.style.fill=color;zones[name].color=color;presetPathEdits[selectedObject.id]={...(presetPathEdits[selectedObject.id]||{}),color};if(zones[name].definitionKey&&legendState[zones[name].definitionKey]){legendState[zones[name].definitionKey].color=color;saveLegend()}savePresetEdits();saveZoneMetadata();renderLayers();renderMaterialTypes();renderUserLayers()}else if(selectedObject.kind==='userLayer'){const layer=userLayers.find(l=>l.id===selectedObject.id);if(layer){layer.color=color;if(layer.type==='polygon'&&zones[layer.name]){zones[layer.name].color=color;saveZoneMetadata()}else layer.overrideColor=color;saveUserLayers();renderUserLayers();renderLayers();renderMaterialTypes()}}else if(selectedObject.kind==='mark'){const mark=markings.find(m=>m.id===selectedObject.id);if(mark){mark.overrideColor=color;saveMarkings();renderMarkings()}}else if(selectedObject.kind==='original'){originalEdits[selectedObject.id]={...(originalEdits[selectedObject.id]||{}),color};applyOriginalEdits();saveOriginalEdits()}};
document.querySelector('#objectSize').oninput=e=>{if(!selectedObject)return;const size=Number(e.target.value);if(selectedObject.kind==='zone'){const scale=Math.max(.2,size/10),path=selectedObject.el,b=path.getBBox(),cx=b.x+b.width/2,cy=b.y+b.height/2;path.setAttribute('transform',`translate(${cx} ${cy}) scale(${scale}) translate(${-cx} ${-cy})`);presetPathEdits[selectedObject.id]={...(presetPathEdits[selectedObject.id]||{}),scale};savePresetEdits()}else if(selectedObject.kind==='userLayer'){const layer=userLayers.find(l=>l.id===selectedObject.id);if(layer){layer.size=size;saveUserLayers();renderUserLayers()}}else if(selectedObject.kind==='mark'){const mark=markings.find(m=>m.id===selectedObject.id);if(mark){mark.size=size;saveMarkings();renderMarkings()}}else{originalEdits[selectedObject.id]={...(originalEdits[selectedObject.id]||{}),size};applyOriginalEdits();saveOriginalEdits()}};
document.querySelector('#objectRotation').oninput=e=>{if(!selectedObject)return;const rotation=Number(e.target.value);if(selectedObject.kind==='original'&&selectedObject.el?.tagName==='text'){originalEdits[selectedObject.id]={...(originalEdits[selectedObject.id]||{}),rotation};applyOriginalEdits();saveOriginalEdits()}else if(selectedObject.kind==='mark'){const mark=markings.find(m=>m.id===selectedObject.id);if(mark?.type==='text'){mark.rotation=rotation;saveMarkings();renderMarkings()}}};
function setEditorMode(mode){editorMode=mode;document.body.classList.toggle('view-mode',mode==='view');document.querySelectorAll('.mode-switch button').forEach(btn=>btn.classList.toggle('active',btn.dataset.mode===mode));if(mode==='view'){if(drawingLayer)cancelLayerDraw();tagging=false;pendingMark=null;document.querySelector('#mapStage').style.cursor='';if(legendEditing)document.querySelector('#editLegend').click();flash('View mode — editing locked')}else{if(!legendEditing)document.querySelector('#editLegend').click();flash('Edit mode — select a legend category')}}
document.querySelectorAll('.mode-switch button').forEach(btn=>btn.onclick=()=>setEditorMode(btn.dataset.mode));
document.querySelector('#undoAction').onclick=()=>{const state=history.pop();if(!state){flash('Nothing to undo');return}restoreSnapshot(state);flash('Last change undone')};
document.querySelector('#deleteSelection').onclick=()=>{if(selectedObject?.kind==='zone'){checkpoint();presetPathEdits[selectedObject.id]={...(presetPathEdits[selectedObject.id]||{}),hidden:true};selectedObject.el.style.display='none';savePresetEdits();document.querySelector('#presetHandles').innerHTML='';document.querySelector('#selectionProperties').hidden=true;selectedObject=null;flash('Material zone removed');return}if(selectedObject?.kind==='userLayer'){const layer=userLayers.find(l=>l.id===selectedObject.id);if(!layer)return;checkpoint();userLayers=userLayers.filter(l=>l.id!==layer.id);if(zones[layer.name]?.custom&&!zones[layer.name].definitionKey&&!userLayers.some(l=>l.name===layer.name))delete zones[layer.name];selectedObject=null;saveUserLayers();renderUserLayers();renderLayers();flash(`${layer.name} shape deleted`);return}if(selectedOriginalId){checkpoint();originalEdits[selectedOriginalId]={...(originalEdits[selectedOriginalId]||{}),hidden:true};saveOriginalEdits();applyLegend();document.querySelectorAll('.original-feature').forEach(x=>x.classList.remove('feature-selected'));selectedOriginalId=null;selectedObject=null;flash('Original feature removed');return}if(editingMarkId){const mark=markings.find(m=>m.id===editingMarkId);if(!mark){flash('Select a map feature first');return}checkpoint();markings=markings.filter(m=>m.id!==editingMarkId);editingMarkId=null;saveMarkings();renderMarkings();renderCustomLegendRows();flash(`${mark.sampleId} deleted`);return}flash('Select a map feature first')};
document.querySelector('#restoreOriginal').onclick=()=>{if(!confirm('Restore the original map? This removes all user-drawn layers, markers, moved labels, feature edits, and legend changes.'))return;checkpoint();Object.keys(zones).forEach(k=>delete zones[k]);Object.assign(zones,JSON.parse(JSON.stringify(baseZones)));userLayers=[];markings=[];originalEdits={};presetPathEdits={};legendState=JSON.parse(JSON.stringify(legendDefaults));hiddenZones.clear();editingMarkId=null;selectedOriginalId=null;selectedObject=null;active='Advanced argillic';panX=0;panY=0;['terratag-user-layers','terratag-markings','terratag-original-edits','terratag-preset-paths','terratag-legend','terratag-zone-data'].forEach(key=>localStorage.removeItem(key));document.querySelectorAll('.preset-zone').forEach(path=>{path.dataset.zone=path.dataset.baseZone;path.setAttribute('d',path.dataset.baseD);path.removeAttribute('transform');path.style.fill='';path.style.opacity=''});document.querySelectorAll('.zone').forEach(z=>z.classList.remove('hidden'));document.querySelectorAll('.original-feature').forEach(x=>x.classList.remove('feature-selected'));document.querySelector('#presetHandles').innerHTML='';document.querySelector('#selectionProperties').hidden=true;applyOriginalEdits();renderUserLayers();renderMarkings();renderLayers();applyLegend();Object.keys(zones).forEach(applyZoneConfidence);selectZone(active);setZoom(.9);flash('Original map restored')};
document.querySelector('#doneEditing').onclick=()=>{saveZoneData();setEditorMode('view')};
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&drawingLayer){cancelLayerDraw();flash('Layer drawing cancelled');return}if(e.key==='Escape'&&tagging){tagging=false;pendingMark=null;document.querySelector('#mapStage').style.cursor='';document.querySelector('#mapHint').textContent='Click a zone to inspect · Add a marking to annotate the section';flash('Placement cancelled')}});
